package main
import "fmt"

func quickSort(nums []int) []int {
	if len(nums) <= 1 {
		return nums
	}

	quick(nums, 0, len(nums)-1)
	return nums
}


func quick(nums []int,left,right int){

      if left >= right{
          return
      }

      pivotIndex := partiton(nums,left,right)

      quick(nums,left,pivotIndex-1)

      quick(nums,pivotIndex+1,right)


}

func partiton(nums []int,left,right int)int{

     pivot := nums[right]

     i:=left

     for j:=left;j<right;j++{
         if nums[j] < pivot{
         nums[i],nums[j] = nums[j],nums[i]
         i++
         }
     }

     nums[i],nums[right] = nums[right],nums[i]

     return i
}

func main() {
	nums := []int{5, 2, 9, 1, 5, 6}
	quickSort(nums)
	fmt.Println(nums)
}
